import torch

def safe_optimizer_step(
    model,
    optimizer,
    loss,
    max_grad_norm: float = 1.0,
    scaler=None,               # GradScaler for AMP
) -> dict:
    """
    Robust optimizer step with gradient clipping, NaN detection,
    and AMP support.
    """
    if scaler is not None:
        # AMP path
        scaler.scale(loss).backward()
        scaler.unscale_(optimizer)  # unscale before clipping
    else:
        loss.backward()

    # Check for NaN gradients before clipping
    has_nan = any(
        p.grad is not None and torch.isnan(p.grad).any()
        for p in model.parameters()
    )
    if has_nan:
        optimizer.zero_grad(set_to_none=True)
        return {"skipped": True, "reason": "nan_gradient"}

    grad_norm = torch.nn.utils.clip_grad_norm_(
        model.parameters(), max_norm=max_grad_norm
    )

    if scaler is not None:
        scaler.step(optimizer)  # skips step if gradients contain inf
        scaler.update()
    else:
        optimizer.step()

    optimizer.zero_grad(set_to_none=True)

    return {
        "skipped": False,
        "grad_norm": grad_norm.item(),
        "loss": loss.item(),
    }
